const plays = $json.liveData?.plays?.allPlays || [];
const gamePk = $item(0).$node["Filter Active Games"].json.gamePk;
const out = [];
for (const p of plays) {
  if (p.result?.eventType !== 'home_run') continue;
  const key = 'seen:' + gamePk + ':' + (p.about?.atBatIndex);
  if (store[key]) continue;
  store[key] = true;
  out.push({ json: { gamePk, play: p } });
}
return out;

